import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ServiceSetting } from '../../core/models';

@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './admin-settings.component.html',
})
export class AdminSettingsComponent {
  settings = signal<ServiceSetting[]>([
    {
      service: 'postgresql',
      label: 'PostgreSQL',
      configured: true,
      fields: [
        { key: 'POSTGRES_HOST', label: 'Host', masked: 'db.internal' },
        { key: 'POSTGRES_PASSWORD', label: 'Password', masked: '••••••••', secret: true },
      ],
    },
    {
      service: 'minio',
      label: 'MinIO (object storage)',
      configured: false,
      fields: [
        { key: 'MINIO_ACCESS_KEY', label: 'Access key', masked: '' },
        { key: 'MINIO_SECRET_KEY', label: 'Secret key', masked: '', secret: true },
      ],
    },
  ]);

  saved = signal(false);

  save(): void {
    this.saved.set(true);
    // service_agent wires this to ApiService.updateSettings.
  }
}
